class Solution {
    public int nextBeautifulNumber(int n) {
        for (int i = n + 1; ; i++) {
            if (isNumericallyBalanced(i)) {
                return i;
            }
        }
    }

    private boolean isNumericallyBalanced(int num) {
        int[] count = new int[10];
        String str = String.valueOf(num);
        for (char c : str.toCharArray()) {
            count[c - '0']++;
        }
        for (char c : str.toCharArray()) {
            if (count[c - '0'] != c - '0') {
                return false;
            }
        }
        return true;
    }
}
```
